'use strict';function setImageSrc(img){img.onload=function(){this.classList.add('loaded')};return img.src=img.getAttribute('data-img-src')}function checkIfBooksInViewport(){var bookImages=document.getElementsByClassName('book-img');var _iteratorNormalCompletion=true;var _didIteratorError=false;var _iteratorError=undefined;try{for(var _iterator=bookImages[Symbol.iterator](),_step;!(_iteratorNormalCompletion=(_step=_iterator.next()).done);_iteratorNormalCompletion=true){var bookImage=_step.value;if(bookImage.classList.contains('loaded')){continue}var rect=bookImage.getBoundingClientRect();if(rect.top>=0&&rect.bottom<=(window.innerHeight||document.documentElement.clientHeight)){setImageSrc(bookImage)}}}catch(err){_didIteratorError=true;_iteratorError=err}finally{try{if(!_iteratorNormalCompletion&&_iterator.return){_iterator.return()}}finally{if(_didIteratorError){throw _iteratorError}}}}var debouncedCheckIfBooksInViewport=debounce(function(){return checkIfBooksInViewport()},250);// borrows from https://gist.github.com/nmsdvid/8807205
